#include <bits/stdc++.h>
using namespace std;
int t;
long long k;
int main(){
	scanf("%d",&t);
	while(t--){
		scanf("%lld",&k);
		if(k==0){
			printf("NO!\n");
			continue;
		}
		long long r=2*k+1;
		int sum=0;
		while(r%2)
			r=(r*r+r)/2,sum++;
		printf("%d\n",sum);
	}
	return 0;
}
